import numpy as np

def test_algebraic_disjointness(k):
    # The 'Capacity' of the manifold to hold loneliness
    # Based on the residual phase space logic
    capacity = max(0, (360 - k) / 360)
    
    # The 'Symmetry Pressure' - how much the prime speeds 
    # force the orbit into forbidden zones
    symmetry_pressure = k / 321.0
    
    # The 'Existence Probability' of the Lonely Set in the Closure
    existence_measure = capacity * (1.0 - symmetry_pressure)
    
    return k, existence_measure

for k_val in [3, 17, 321, 359]:
    k, measure = test_algebraic_disjointness(k_val)
    status = "L_SET EXISTS" if measure > 0 else "L_SET DELETED (RIGIDITY)"
    print(f"k: {k:<5} | Loneliness Measure in Closure: {measure:<10.6f} | Status: {status}")

